//! # Trade-offs
//!
//! - Keeps two copies of state, increasing memory use.
//! - Optimizes reads at the cost of slower writes.

/// ```no_run
/// # fn main() -> Result<(), Error> {
/// let mut client = ClientBuilder::new("localhost", 993).connect()?;
/// let mut session = client.login("user", "pass")?;
/// let inbox = session.select("INBOX")?;
/// # Ok(())
/// # }
/// ```

